def _shade(c, x, y):
    return (FONT[(c & 0x7f) * 16 + y * 2 + (x >> 2)] >> ((x & 3) * 2)) & 3


def render_text(pg, text, fg=None, outline=None, mid=None, bg=None):
    """Render `text` to a PAL8 pg.Bitmap (index 0 transparent unless `bg` given).
    Shades: 0->bg/transparent, 1->outline, 2->mid, 3->fg. Supports '\n'. Returns (bitmap, w, h)."""
    fg = pg.rgb565(255, 255, 255) if fg is None else fg
    outline = pg.rgb565(0, 0, 0) if outline is None else outline
    mid = pg.rgb565(160, 160, 160) if mid is None else mid
    import array
    pal = array.array("H", (bg if bg is not None else 0, outline, mid, fg))
    lines = text.split("\n")
    cols = max((len(s) for s in lines), default=0)
    w = cols * GLYPH_W
    h = len(lines) * GLYPH_H
    if w == 0 or h == 0:
        w = h = 1
    data = bytearray(w * h)
    for row, s in enumerate(lines):
        oy = row * GLYPH_H
        for i in range(len(s)):
            c = ord(s[i])
            ox = i * GLYPH_W
            for y in range(GLYPH_H):
                base = (oy + y) * w + ox
                for x in range(GLYPH_W):
                    sh = _shade(c, x, y)
                    if sh:
                        data[base + x] = sh
    bmp = pg.Bitmap(data, w, h, format=pg.PAL8, palette=pal, frames=1, stride=w, transparent=(0 if bg is None else None))
    return bmp, w, h
